class Shape
{
public:
    virtual double area() = 0; // pure virtual function — note the = 0
};

#include <iostream>

using namespace std;

class Shape
{
public:
    virtual double area() = 0;
};

class Circle : public Shape
{
private:
    double radius;

public:
    Circle(double r)
    {
        radius = r;
    }

    double area() override
    {
        return 3.14159 * radius * radius;
    }
};

int main()
{
    Shape *s = new Circle(5);

    cout << s->area() << endl;

    delete s;

    return 0;
}

class Rectangle : public Shape
{
private:
    double width, height;

public:
    Rectangle(double w, double h) { width = w; height = h; }

    double area() override
    {
        return width * height;
    }
};

Shape *shapes[2];
shapes[0] = new Circle(5);
shapes[1] = new Rectangle(4, 6);

for (int i = 0; i < 2; i++)
{
    cout << shapes[i]->area() << endl; // each calls its OWN correct area()
}

